     9→ * and the given input Object as the input.
    10→ * @author D. X. Nguyen
    11→ * @author S. B. Wong
    12→ */
    13→public class MTList implements IList {
    14→	/**
    15→	 * Singleton Pattern
    16→	 */
    17→	public final static MTList Singleton = new MTList();
    18→
    19→	/**
    20→	 * Private constructor for the Singleton
    21→	 */
    22→	private MTList() {
    23→	}
    24→
    25→	/**
    26→	 * Calls the empty case of the algorithm algo, passing to it itself as
    27→	 * the host parameter and the given input inp as the input parameter.
    28→	 * This method is marked as final to prevent all subclasses from
    29→	 * overriding it.  Finalizing a method also allows the compiler to generate
    30→	 * more efficient calling code.
    31→	 */
    32→	public final Object execute(IListAlgo algo, Object... inp) {
    33→		return algo.emptyCase(this, inp);
    34→	}
