public class LargestFwdAlgo implements IListAlgo {

	@Override
	/**
	 * The base case value is Min_Value,
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return Integer.MIN_VALUE;
	}

	@Override
	/**
	 * Pass the first value to the rest of the list, using a helper visitor, to be accumulated.
	 */
	public Object nonEmptyCase(NEList host, Object... nu) {
		// Use the LargestAcc helper to accumulate the maximum value
		LargestAcc acc = new LargestAcc();
		// Initialize with the first element
		acc.accumulate(host.getFirst());
		// Recursively process the rest with a helper that updates the accumulator
		host.getRest().execute(new IListAlgo() {
			@Override
			public Object emptyCase(MTList h, Object... params) {
				return acc.getValue();
			}

			@Override
			public Object nonEmptyCase(NEList h, Object... params) {
				acc.accumulate(h.getFirst());
				return h.getRest().execute(this);
			}
		});
		return acc.getValue();
	}

}

