/**
 *  Return a boolean indicating whether or not a given element is in the list.
 *  The input parameter is a String that needs to be parsed as an int.
 * @author Son Nguyen and Charlie Lockyer
 *
 */
public class ContainFwdAlgo implements IListAlgo {

	@Override
	/**
	 * The base case value is false.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return false;
	}

	@Override
	/**
	 * Pass the search value to the rest of the list, checking each element.
	 * Return true once found, otherwise continue searching the rest.
	 */
	public Object nonEmptyCase(NEList host, Object... params) {
		// Parse the search value from the parameter
		int searchValue = Integer.parseInt((String) params[0]);

		// Check if the first element matches
		if ((int) host.getFirst() == searchValue) {
			return true;
		}

		// Otherwise, recursively search the rest with the same search value
		return host.getRest().execute(new ContainFwdAlgo(), params);
	}

}

