/**
 * Return a list with the smallest element from the list removed.
 * Do this with a single pass through the the list!
 * The input parameter is not used ("nu").
 * @author Son Nguyen and Charlie Lockyer
 */
public class RemoveSmallestRevAlgo implements IListAlgo {

	/**
	 * Helper class to track both the resulting list and the minimum value found
	 */
	private static class ListWithMin {
		IList list;
		int minValue;

		ListWithMin(IList list, int minValue) {
			this.list = list;
			this.minValue = minValue;
		}
	}

	/**
	 * Returns empty list with MAX_VALUE as the sentinel minimum.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return new ListWithMin(MTList.Singleton, Integer.MAX_VALUE);
	}

	/**
	 * Process the rest first (reverse accumulation), then decide whether to skip
	 * or include the current element based on which is smaller.
	 */
	public Object nonEmptyCase(NEList host, Object... nu) {
		// Process the rest of the list first
		ListWithMin restResult = (ListWithMin) host.getRest().execute(this);

		int currentValue = (int) host.getFirst();
		int restMin = restResult.minValue;

		// If current value is smaller than all in the rest, skip it
		// and the minimum of the whole list is the current value
		if (currentValue <= restMin) {
			return new ListWithMin(restResult.list, currentValue);
		} else {
			// Otherwise, prepend current value to the result list
			// and the minimum is what we found in the rest
			IList newList = new NEList(host.getFirst(), restResult.list);
			return new ListWithMin(newList, restMin);
		}
	}

}

