/**
 * Returns max between first and rest
 */
public Object nonEmptyCase(NEList host, Object... nu) {
	int currentValue = (int) host.getFirst();
	int maxOfRest = (int) host.getRest().execute(this);
	return Math.max(currentValue, maxOfRest);
}

