/**
 * Returns first plus the result of the rest of the list.
 */
public Object nonEmptyCase(NEList host, Object... param) {
	// Process the rest first (reverse accumulation)
	boolean foundInRest = (boolean) host.getRest().execute(this, param);

	// If found in rest, return true
	if (foundInRest) {
		return true;
	}

	// Otherwise check if current element matches the search value
	int searchValue = (int) param[0];
	int currentValue = (int) host.getFirst();
	return currentValue == searchValue;
}

